import copperhead as cp

@cp.compile(target="rust")
def sum_list(numbers: list[cp.f64]) -> cp.f64:
    total = cp.f64(0)
    for num in numbers:
        total += num
    return total

import copperhead as cp

@cp.compile(target="rust")
def find_max(numbers: list[cp.f64]) -> cp.f64:
    if len(numbers) == 0:
        return cp.f64(0)
    max_val = numbers[0]
    for num in numbers:
        if num > max_val:
            max_val = num
    return max_val

