@cp.compile(target="rust")
def count_occurrences(items: list[cp.i64], target: cp.i64) -> cp.i64:
    count = 0
    for item in items:
        if item == target:
            count += 1
    return count

import copperhead as cp

@cp.compile(target="rust")
def fibonacci(n: cp.i64) -> cp.i64:
    if n <= 0:
        return 0
    if n == 1:
        return 1
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b

import copperhead as cp

@cp.compile(target="rust")
def is_prime(n: cp.i64) -> cp.bool:
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

