@cp.compile(target="rust")
def factorial(n: cp.i64) -> cp.i64:
    if n <= 1:
        return 1
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

import copperhead as cp

@cp.compile(target="rust")
def prime_sieve(n: cp.i64) -> list[cp.i64]:
    if n < 2:
        return []
    sieve = [True] * (n + 1)
    sieve[0] = False
    sieve[1] = False
    i = 2
    while i * i <= n:
        if sieve[i]:
            j = i * i
            while j <= n:
                sieve[j] = False
                j += i
        i += 1
    result = []
    for i in range(2, n + 1):
        if sieve[i]:
            result.append(i)
    return result

