@cp.compile(target="rust")
def bubble_sort(arr: list[cp.f64]) -> list[cp.f64]:
    n = len(arr)
    result = list(arr)
    for i in range(n):
        for j in range(0, n - i - 1):
            if result[j] > result[j + 1]:
                result[j], result[j + 1] = result[j + 1], result[j]
    return result

import copperhead as cp

@cp.compile(target="rust")
def quick_sort(arr: list[cp.f64]) -> list[cp.f64]:
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = []
    middle = []
    right = []
    for x in arr:
        if x < pivot:
            left.append(x)
        elif x == pivot:
            middle.append(x)
        else:
            right.append(x)
    left = quick_sort(left)
    right = quick_sort(right)
    result = left + middle + right
    return result

import copperhead as cp

@cp.compile(target="rust")
def merge_sort(arr: list[cp.f64]) -> list[cp.f64]:
    if len(arr) <= 1:
        return arr
    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])
    result = []
    i = 0
    j = 0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1
    while i < len(left):
        result.append(left[i])
        i += 1
    while j < len(right):
        result.append(right[j])
        j += 1
    return result

import copperhead as cp

@cp.compile(target="rust")
def insertion_sort(arr: list[cp.f64]) -> list[cp.f64]:
    result = list(arr)
    for i in range(1, len(result)):
        key = result[i]
        j = i - 1
        while j >= 0 and result[j] > key:
            result[j + 1] = result[j]
            j -= 1
        result[j + 1] = key
    return result

