@cp.compile(target="rust")
def linear_search(arr: list[cp.i64], target: cp.i64) -> cp.i64:
    for i in range(len(arr)):
        if arr[i] == target:
            return i
    return -1

import copperhead as cp

@cp.compile(target="rust")
def binary_search(arr: list[cp.i64], target: cp.i64) -> cp.i64:
    lo = 0
    hi = len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

