@cp.compile(target="rust")
def stddev(data: list[cp.f64]) -> cp.f64:
    n = len(data)
    if n == 0:
        return cp.f64(0)
    mean = cp.f64(0)
    for x in data:
        mean += x
    mean = mean / n
    ssd = cp.f64(0)
    for x in data:
        diff = x - mean
        ssd += diff * diff
    return cp.math.sqrt(ssd / n)

