@cp.compile(target="rust")
def median(data: list[cp.f64]) -> cp.f64:
    n = len(data)
    if n == 0:
        return cp.f64(0)
    sorted_data = sorted(data)
    mid = n // 2
    if n % 2 == 0:
        return (sorted_data[mid - 1] + sorted_data[mid]) / 2.0
    return sorted_data[mid]

