@cp.compile(target="rust")
def moving_average(data: list[cp.f64], window: cp.i64) -> list[cp.f64]:
    n = len(data)
    w = window
    result = []
    for i in range(n - w + 1):
        s = cp.f64(0)
        for j in range(w):
            s += data[i + j]
        result.append(s / w)
    return result

