@cp.compile(target="rust")
def pearson_correlation(x: list[cp.f64], y: list[cp.f64]) -> cp.f64:
    n = len(x)
    if n == 0 or n != len(y):
        return cp.f64(0)
    sum_x = cp.f64(0)
    sum_y = cp.f64(0)
    sum_xy = cp.f64(0)
    sum_x2 = cp.f64(0)
    sum_y2 = cp.f64(0)
    for i in range(n):
        sum_x += x[i]
        sum_y += y[i]
        sum_xy += x[i] * y[i]
        sum_x2 += x[i] * x[i]
        sum_y2 += y[i] * y[i]
    numerator = n * sum_xy - sum_x * sum_y
    denominator = cp.math.sqrt((n * sum_x2 - sum_x * sum_x) * (n * sum_y2 - sum_y * sum_y))
    if denominator == 0.0:
        return cp.f64(0)
    return numerator / denominator

