@cp.compile(target="rust")
def matrix_transpose(m: list[list[cp.f64]]) -> list[list[cp.f64]]:
    rows = len(m)
    cols = len(m[0])
    result = [[cp.f64(0) for _ in range(rows)] for _ in range(cols)]
    for i in range(rows):
        for j in range(cols):
            result[j][i] = m[i][j]
    return result

