@cp.compile(target="rust")
def euclidean_distance(a: list[cp.f64], b: list[cp.f64]) -> cp.f64:
    n = len(a)
    ssd = cp.f64(0)
    for i in range(n):
        diff = a[i] - b[i]
        ssd += diff * diff
    return cp.math.sqrt(ssd)

