@cp.compile(target="rust")
def manhattan_distance(a: list[cp.f64], b: list[cp.f64]) -> cp.f64:
    n = len(a)
    total = cp.f64(0)
    for i in range(n):
        diff = a[i] - b[i]
        if diff < 0.0:
            diff = -diff
        total += diff
    return total

import copperhead as cp

@cp.compile(target="rust")
def cosine_similarity(a: list[cp.f64], b: list[cp.f64]) -> cp.f64:
    n = len(a)
    dot = cp.f64(0)
    norm_a = cp.f64(0)
    norm_b = cp.f64(0)
    for i in range(n):
        dot += a[i] * b[i]
        norm_a += a[i] * a[i]
        norm_b += b[i] * b[i]
    if norm_a == 0.0 or norm_b == 0.0:
        return cp.f64(0)
    return dot / (cp.math.sqrt(norm_a) * cp.math.sqrt(norm_b))

