@cp.compile(target="rust")
def levenshtein(s1: str, s2: str) -> cp.i64:
    m = len(s1)
    n = len(s2)
    if m == 0:
        return n
    if n == 0:
        return m
    prev = list(range(n + 1))
    for i in range(1, m + 1):
        curr = [i] + [0] * n
        for j in range(1, n + 1):
            cost = 1
            if s1[i - 1] == s2[j - 1]:
                cost = 0
            curr[j] = min(prev[j] + 1, curr[j - 1] + 1, prev[j - 1] + cost)
        prev = curr
    return prev[n]

import copperhead as cp

@cp.compile(target="rust")
def reverse_string(s: str) -> str:
    chars = list(s)
    i = 0
    j = len(chars) - 1
    while i < j:
        chars[i], chars[j] = chars[j], chars[i]
        i += 1
        j -= 1
    return "".join(chars)

import copperhead as cp

@cp.compile(target="rust")
def count_words(s: str) -> cp.i64:
    count = 0
    in_word = False
    for ch in s:
        if ch != " " and ch != "\t" and ch != "\n":
            if not in_word:
                count += 1
                in_word = True
        else:
            in_word = False
    return count

