@cp.compile(target="rust")
def build_histogram(data: list[cp.f64], bins: cp.i64) -> list[cp.i64]:
    if len(data) == 0 or bins <= 0:
        return []
    lo = data[0]
    hi = data[0]
    for x in data:
        if x < lo:
            lo = x
        if x > hi:
            hi = x
    if hi == lo:
        return [len(data)]
    width = (hi - lo) / bins
    counts = [0] * bins
    for x in data:
        idx = int((x - lo) / width)
        if idx >= bins:
            idx = bins - 1
        counts[idx] += 1
    return counts

import copperhead as cp

@cp.compile(target="rust")
def normalize(data: list[cp.f64]) -> list[cp.f64]:
    if len(data) == 0:
        return []
    lo = data[0]
    hi = data[0]
    for x in data:
        if x < lo:
            lo = x
        if x > hi:
            hi = x
    if hi == lo:
        return [cp.f64(0) for _ in data]
    rng = hi - lo
    result = []
    for x in data:
        result.append((x - lo) / rng)
    return result

import copperhead as cp

@cp.compile(target="rust")
def convolve_1d(signal: list[cp.f64], kernel: list[cp.f64]) -> list[cp.f64]:
    n = len(signal)
    k = len(kernel)
    result = []
    for i in range(n - k + 1):
        s = cp.f64(0)
        for j in range(k):
            s += signal[i + j] * kernel[j]
        result.append(s)
    return result

import copperhead as cp

@cp.compile(target="rust")
def zscore(data: list[cp.f64]) -> list[cp.f64]:
    n = len(data)
    if n == 0:
        return []
    mean = cp.f64(0)
    for x in data:
        mean += x
    mean = mean / n
    ssd = cp.f64(0)
    for x in data:
        diff = x - mean
        ssd += diff * diff
    sd = cp.math.sqrt(ssd / n)
    if sd == 0.0:
        return [cp.f64(0) for _ in data]
    result = []
    for x in data:
        result.append((x - mean) / sd)
    return result

import copperhead as cp

@cp.compile(target="rust")
def sqrt_newton(x: cp.f64) -> cp.f64:
    if x < 0.0:
        return cp.f64(0)
    if x == 0.0:
        return cp.f64(0)
    guess = x
    for _ in range(100):
        new_guess = (guess + x / guess) / 2.0
        diff = new_guess - guess
        if diff < 0.0:
            diff = -diff
        if diff < 1e-10:
            return new_guess
        guess = new_guess
    return guess
